// build-shopify-theme — Validate Theme Input
// Validates store_blueprint (theme_sections + assets) and runtime_config.
// SAFETY: Checks for allow_theme_writes opt-in. Defaults to dry_run mode.
//
// PHASE 7B.3 STATUS: SCAFFOLD — live writes require allow_theme_writes: true in runtime_config.
// Without opt-in, this workflow returns PHASE_7B3_DRY_RUN with a plan of what would be written.

const input = $input.first().json;

const runtimeConfig   = input.runtime_config   || {};
const storeBlueprint  = input.store_blueprint   || null;
const contentStrategy = input.content_strategy  || {};
const projectId       = input.project_id        || runtimeConfig.project_id || null;

if (!projectId) {
  throw new Error('MISSING_RUNTIME_CONFIG: build-shopify-theme requires project_id (top-level) or runtime_config.project_id');
}

if (!storeBlueprint) {
  throw new Error('MISSING_ARTIFACT: store_blueprint is required but was not found in trigger input');
}

const themeSections = storeBlueprint.theme_sections || [];
const assets        = storeBlueprint.assets         || [];

if (themeSections.length === 0 && assets.length === 0) {
  throw new Error('INVALID_BLUEPRINT: store_blueprint.theme_sections and store_blueprint.assets are both empty — nothing to deploy');
}

// ── Shopify config ────────────────────────────────────────────────────────
const shopUrl    = runtimeConfig.shopify_shop_url    || runtimeConfig.shop_url    || runtimeConfig.STORE_OS_SHOPIFY_SHOP_URL    || null;
const apiVersion = runtimeConfig.shopify_api_version || runtimeConfig.api_version || runtimeConfig.STORE_OS_SHOPIFY_API_VERSION || '2025-01';

if (!shopUrl) {
  throw new Error('MISSING_CONFIG: shop_url not found in runtime_config.');
}

const shopDomain  = shopUrl.replace(/^https?:\/\//, '').replace(/\/$/, '');
const shopifyBase = 'https://' + shopDomain + '/admin/api/' + apiVersion;

// ── Safety opt-in check ───────────────────────────────────────────────────
// allow_theme_writes must be explicitly set to true to perform any writes.
// This prevents accidental theme modifications during automated/unattended runs.
const allowThemeWrites = runtimeConfig.allow_theme_writes === true
  || runtimeConfig.allow_theme_writes === 'true';

// Target theme: specified theme ID or will use active theme (requires confirmation)
const targetThemeId = runtimeConfig.shopify_theme_id || null;

console.log(
  `build-shopify-theme: project=${projectId}, shop=${shopDomain}, ` +
  `sections=${themeSections.length}, assets=${assets.length}, ` +
  `allow_theme_writes=${allowThemeWrites}, target_theme_id=${targetThemeId || 'auto-detect'}`
);

return [{
  json: {
    project_id:        projectId,
    runtime_config:    runtimeConfig,
    store_blueprint:   storeBlueprint,
    content_strategy:  contentStrategy,
    shop_url:          shopUrl,
    shop_domain:       shopDomain,
    api_version:       apiVersion,
    shopify_base:      shopifyBase,
    allow_theme_writes: allowThemeWrites,
    target_theme_id:   targetThemeId,
    theme_sections:    themeSections,
    assets:            assets,
    sections_count:    themeSections.length,
    assets_count:      assets.length,
  },
}];

// build-shopify-theme — Dry Run Plan
// allow_theme_writes is not set (or false). Return a plan of what would be written without performing any writes.
// Returns PHASE_7B3_DRY_RUN with the full planned write operations.

const validated     = $input.first().json;
const projectId     = validated.project_id;
const shopDomain    = validated.shop_domain;
const blueprint     = validated.store_blueprint;
const themeSections = validated.theme_sections;
const assets        = validated.assets;

// ── Plan section writes ────────────────────────────────────────────────────
const dryRunPlan = [];

for (const section of themeSections) {
  // Shopify Dawn/OS 2.0 section file key pattern: sections/{type}.json
  const sectionType = (section.section_type || 'unknown').toLowerCase().replace(/[^a-z0-9-]/g, '-');
  const key = 'sections/' + sectionType + '.json';

  dryRunPlan.push({
    operation:    'write_section',
    key:          key,
    section_type: sectionType,
    page:         section.page || 'homepage',
    order:        section.order || null,
    heading_hint: section.heading_hint || null,
    reason:       `Blueprint requests ${sectionType} section on ${section.page || 'homepage'} (order ${section.order || '?'})`,
  });
}

for (const asset of assets) {
  const assetType = (asset.asset_type || 'unknown').toLowerCase();
  let key;
  if (assetType === 'logo')       key = 'assets/logo.png';
  else if (assetType === 'favicon') key = 'assets/favicon.ico';
  else if (assetType === 'hero-image') key = 'assets/hero.jpg';
  else key = 'assets/' + assetType + '.png';

  dryRunPlan.push({
    operation: 'write_asset',
    key:       key,
    asset_type: assetType,
    purpose:   asset.purpose || null,
    dimensions: asset.dimensions || null,
    reason:    `Blueprint requests ${assetType} asset: ${asset.purpose || key} (${asset.dimensions || 'dimensions not specified'})`,
  });
}

console.log(
  `Dry Run Plan: planned ${dryRunPlan.filter(p=>p.operation==='write_section').length} section writes, ` +
  `${dryRunPlan.filter(p=>p.operation==='write_asset').length} asset writes. No live writes performed.`
);

return [{
  json: {
    status:          'PHASE_7B3_DRY_RUN',
    project_id:      projectId,
    shop_url:        shopDomain,
    theme_id:        null,
    theme_name:      null,
    completed_at:    new Date().toISOString(),

    sections_written: 0,
    assets_written:   0,
    dry_run:          true,
    dry_run_plan:     dryRunPlan,

    errors:   [],
    warnings: [
      'allow_theme_writes not set — no writes performed. Set runtime_config.allow_theme_writes: true to enable live theme deployment.',
    ],

    blueprint_summary: {
      theme_sections_in_blueprint: themeSections.length,
      assets_in_blueprint:         assets.length,
    },

    safety_notes: [
      'DRY RUN ONLY — no Shopify theme assets were written',
      'To enable live writes: set runtime_config.allow_theme_writes: true and runtime_config.shopify_theme_id to a development theme ID',
      'NEVER target the active production theme without manual review of the dry run plan',
    ],
  },
}];

// build-shopify-theme — Live Deployment Placeholder
// allow_theme_writes: true was detected. This node is a PLACEHOLDER for the live deployment path.
// When Phase 7B.3 is fully implemented, this will be replaced by:
//   Fetch Theme ID → Fetch Existing Assets → Build Write Plan → Write Section Assets → Write Other Assets → Compile Summary
//
// For now: return the dry run plan as PHASE_7B3_DRY_RUN with a note that live writes are not yet implemented.
// This prevents accidental partial execution while the implementation is completed.

const validated     = $input.first().json;
const projectId     = validated.project_id;
const shopDomain    = validated.shop_domain;
const themeSections = validated.theme_sections;
const assets        = validated.assets;

const dryRunPlan = [];

for (const section of themeSections) {
  const sectionType = (section.section_type || 'unknown').toLowerCase().replace(/[^a-z0-9-]/g, '-');
  dryRunPlan.push({
    operation:    'write_section',
    key:          'sections/' + sectionType + '.json',
    section_type: sectionType,
    page:         section.page || 'homepage',
    order:        section.order || null,
    heading_hint: section.heading_hint || null,
    reason:       `Blueprint requests ${sectionType} section (live write pending Phase 7B.3 full implementation)`,
  });
}

for (const asset of assets) {
  const assetType = (asset.asset_type || 'unknown').toLowerCase();
  const keyMap = { logo: 'assets/logo.png', favicon: 'assets/favicon.ico', 'hero-image': 'assets/hero.jpg' };
  dryRunPlan.push({
    operation: 'write_asset',
    key:       keyMap[assetType] || 'assets/' + assetType + '.png',
    asset_type: assetType,
    purpose:   asset.purpose || null,
    dimensions: asset.dimensions || null,
    reason:    `Blueprint requests ${assetType} asset (live write pending Phase 7B.3 full implementation)`,
  });
}

console.log('Phase 7B.3 live path: NOT YET IMPLEMENTED. Returning dry run plan.');

return [{
  json: {
    status:          'PHASE_7B3_DRY_RUN',
    project_id:      projectId,
    shop_url:        shopDomain,
    theme_id:        validated.target_theme_id || null,
    theme_name:      null,
    completed_at:    new Date().toISOString(),

    sections_written: 0,
    assets_written:   0,
    dry_run:          true,
    dry_run_plan:     dryRunPlan,

    errors:   [],
    warnings: [
      'Phase 7B.3 live deployment is not yet implemented. allow_theme_writes: true was detected but live writes were not performed.',
      'Implement the live path: Fetch Theme ID → Fetch Existing Assets → Build Write Plan → Write Section Assets → Write Assets → Compile Summary',
    ],

    blueprint_summary: {
      theme_sections_in_blueprint: themeSections.length,
      assets_in_blueprint:         assets.length,
    },

    safety_notes: [
      'SCAFFOLD ONLY — live theme asset writes are not yet implemented in this workflow',
      'When implemented: target only development/preview themes; validate dry run plan before enabling live writes',
    ],
  },
}];
